using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

/// <summary>
/// Provides helper methods for creating in-memory database contexts for testing.
/// </summary>
internal static class TestHelpers
{
    /// <summary>
    /// Creates a fresh SchoolContext backed by an in-memory database.
    /// Each call produces a unique database name to ensure test isolation.
    /// </summary>
    public static SchoolContext CreateInMemoryContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;

        var context = new SchoolContext(options);
        return context;
    }

    /// <summary>
    /// Seeds the context with a standard set of test data.
    /// </summary>
    public static void SeedTestData(SchoolContext context)
    {
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        context.Departments.Add(department);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 1 }
        };
        context.Courses.AddRange(courses);

        var students = new[]
        {
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2010, 9, 1) },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2012, 9, 1) },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2013, 9, 1) }
        };
        context.Students.AddRange(students);

        var instructors = new[]
        {
            new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(1995, 3, 11) },
            new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2002, 7, 6) }
        };
        context.Instructors.AddRange(instructors);

        context.SaveChanges();
    }
}

