using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_WithItems_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Constructor_WithItems_CalculatesTotalPages()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(4, result.TotalPages); // ceil(10/3) = 4
    }

    [TestMethod]
    public void Constructor_WithItems_ContainsAllItems()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 3);

        // Assert
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual("a", result[0]);
        Assert.AreEqual("b", result[1]);
        Assert.AreEqual("c", result[2]);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
    public void Constructor_VariousCounts_CalculatesCorrectTotalPages(int count, int pageSize, int expectedTotalPages)
    {
        // Arrange & Act
        var result = new PaginatedList<string>(new List<string>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var result = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Act & Assert
        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var result = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Act & Assert
        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var result = new PaginatedList<string>(new List<string>(), 10, 2, 5);

        // Act & Assert
        Assert.IsFalse(result.HasNextPage); // TotalPages = 2, PageIndex = 2
    }

    [TestMethod]
    public void HasNextPage_NotOnLastPage_ReturnsTrue()
    {
        // Arrange
        var result = new PaginatedList<string>(new List<string>(), 10, 1, 5);

        // Act & Assert
        Assert.IsTrue(result.HasNextPage); // TotalPages = 2, PageIndex = 1
    }

    [TestMethod]
    public void Create_ReturnsCorrectPageOfItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]); // Page 2 starts at item 6
        Assert.AreEqual(10, result[4]); // Page 2 ends at item 10
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages); // 20/5 = 4
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 12).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 5);

        // Assert
        Assert.AreEqual(2, result.Count); // Only 2 items on last page
        Assert.AreEqual(11, result[0]);
        Assert.AreEqual(12, result[1]);
    }
}

