using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System.Linq;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicateData()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();
        DbInitializer.Initialize(context);
        var initialStudentCount = context.Students.Count();

        // Act - Call again
        DbInitializer.Initialize(context);

        // Assert - Counts should not change
        Assert.AreEqual(initialStudentCount, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SeedsSpecificStudentNames()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.IsTrue(context.Students.Any(s => s.LastName == "Alexander" && s.FirstMidName == "Carson"));
        Assert.IsTrue(context.Students.Any(s => s.LastName == "Alonso" && s.FirstMidName == "Meredith"));
        Assert.IsTrue(context.Students.Any(s => s.LastName == "Olivetto" && s.FirstMidName == "Nino"));
    }

    [TestMethod]
    public void Initialize_SeedsCourseWithCorrectCredits()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);
        Assert.AreEqual(1050, chemistry.CourseID);
    }

    [TestMethod]
    public void Initialize_SeedsDepartmentsWithBudgets()
    {
        // Arrange
        using var context = TestHelpers.CreateInMemoryContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var english = context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000m, english.Budget);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000m, math.Budget);
    }
}

