using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context;
    private HomeController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_ReturnsViewResult()
    {
        // Act
        var result = _controller.Contact();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewResult()
    {
        // Act
        var result = _controller.Unauthorized();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        // Act
        _controller.Unauthorized();

        // Assert
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void About_WithNoStudents_ReturnsEmptyList()
    {
        // Arrange - no students in context

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedData()
    {
        // Arrange
        var date1 = new DateTime(2010, 9, 1);
        var date2 = new DateTime(2012, 9, 1);

        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "Student1", EnrollmentDate = date1 },
            new Student { FirstMidName = "B", LastName = "Student2", EnrollmentDate = date1 },
            new Student { FirstMidName = "C", LastName = "Student3", EnrollmentDate = date2 }
        );
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group1 = model.Single(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group1.StudentCount);

        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2.StudentCount);
    }
}

