using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using System;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context;
    private DepartmentsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedDepartments()
    {
        var instructor = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = new DateTime(1995, 3, 11)
        };
        _context.Instructors.Add(instructor);

        _context.Departments.AddRange(
            new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000m, StartDate = new DateTime(2007, 9, 1), InstructorID = 1 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000m, StartDate = new DateTime(2007, 9, 1) },
            new Department { DepartmentID = 3, Name = "English", Budget = 200000m, StartDate = new DateTime(2007, 9, 1) }
        );
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as System.Collections.Generic.List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Engineering", model.Name);
        Assert.AreEqual(350000m, model.Budget);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        SeedDepartments();
        var department = new Department
        {
            Name = "New Department",
            Budget = 500000m,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = 1
        };

        // Act
        var result = _controller.Create(department) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_AddsToDatabase()
    {
        // Arrange
        SeedDepartments();
        var department = new Department
        {
            Name = "New Department",
            Budget = 500000m,
            StartDate = new DateTime(2023, 1, 1),
            InstructorID = 1
        };

        // Act
        _controller.Create(department);

        // Assert
        var saved = _context.Departments.Single(d => d.Name == "New Department");
        Assert.AreEqual(500000m, saved.Budget);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedDepartments();
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        // Act
        var result = _controller.Create(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Edit GET Tests ---

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Edit(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Engineering", model.Name);
    }

    // --- Edit POST Tests ---

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        // Arrange
        SeedDepartments();
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering Updated",
            Budget = 400000m,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 1
        };

        // Detach existing entity to avoid tracking conflict
        var existing = _context.Departments.Find(1);
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        // Act
        var result = _controller.Edit(department) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedDepartments();
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1 };

        // Act
        var result = _controller.Edit(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("Engineering", model.Name);
    }

    // --- DeleteConfirmed Tests ---

    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        // Arrange
        SeedDepartments();

        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesDepartmentFromDatabase()
    {
        // Arrange
        SeedDepartments();
        var initialCount = _context.Departments.Count();

        // Act
        _controller.DeleteConfirmed(1);

        // Assert
        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
        Assert.IsNull(_context.Departments.Find(1));
    }
}

