public sealed class InstructorsControllerTests
{
    private SchoolContext _context;
    private InstructorsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private void SeedInstructorsWithCourses()
    {
        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000m,
            StartDate = new DateTime(2007, 9, 1)
        };
        _context.Departments.Add(department);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
        };
        _context.Courses.AddRange(courses);

        var instructors = new[]
        {
            new Instructor
            {
                ID = 1,
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(1995, 3, 11),
                OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Smith 17" },
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { InstructorID = 1, CourseID = 1050 }
                }
            },
            new Instructor
            {
                ID = 2,
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = new DateTime(2002, 7, 6),
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { InstructorID = 2, CourseID = 4022 }
                }
            }
        };
        _context.Instructors.AddRange(instructors);
        _context.SaveChanges();
    }

    // --- Index Tests ---

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithInstructors()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_SetsCoursesForInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Index(1, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Chemistry", model.Courses.First().Title);
    }

    [TestMethod]
    public void Index_InstructorsOrderedByLastName()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        var instructors = model.Instructors.ToList();
        Assert.AreEqual("Abercrombie", instructors[0].LastName);
        Assert.AreEqual("Fakhouri", instructors[1].LastName);
    }

    // --- Details Tests ---

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Details(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Abercrombie", model.LastName);
        Assert.AreEqual("Kim", model.FirstMidName);
    }

    // --- Create GET Tests ---

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
        Assert.AreEqual(0, model.CourseAssignments.Count);
    }

    // --- Create POST Tests ---

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        // Act
        var result = _controller.Create(instructor, null) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_AddsToDatabase()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };

        // Act
        _controller.Create(instructor, null);

        // Assert
        var saved = _context.Instructors.Single(i => i.LastName == "Instructor");
        Assert.AreEqual("New", saved.FirstMidName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = new DateTime(2020, 1, 1)
        };
        var selectedCourses = new[] { "1050", "4022" };

        // Act
        _controller.Create(instructor, selectedCourses);

        // Assert
        Assert.AreEqual(2, instructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        SeedInstructorsWithCourses();
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    // --- Delete GET Tests ---

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual((int)HttpStatusCode.BadRequest, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.Delete(1) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Abercrombie", model.LastName);
    }

    // --- DeleteConfirmed Tests ---

    [TestMethod]
    public void DeleteConfirmed_ValidId_RedirectsToIndex()
    {
        // Arrange
        SeedInstructorsWithCourses();

        // Act
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorFromDatabase()
    {
        // Arrange
        SeedInstructorsWithCourses();
        var initialCount = _context.Instructors.Count();

        // Act
        _controller.DeleteConfirmed(1);

        // Assert
        Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
        Assert.IsNull(_context.Instructors.Find(1));
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorIsDeptAdmin_ClearsDepartmentAdmin()
    {
        // Arrange
        SeedInstructorsWithCourses();
        // Assign instructor 1 as administrator
        var dept = _context.Departments.Find(1);
        dept.InstructorID = 1;
        _context.SaveChanges();

        // Act
        _controller.DeleteConfirmed(1);

        // Assert
        var updatedDept = _context.Departments.Find(1);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

