using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context;
    private NotificationsController _controller;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    [TestMethod]
    public void GetNotifications_NoMessages_ReturnsEmptyList()
    {
        // Drain any existing messages in the static queue
        using var tempService = new NotificationService();
        while (tempService.ReceiveNotification() != null) { }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void GetNotifications_WithMessages_ReturnsNotifications()
    {
        // Arrange - Send a notification first
        using var service = new NotificationService();
        // Drain existing
        while (service.ReceiveNotification() != null) { }
        service.SendNotification("Course", "1", "Test Course", EntityOperation.CREATE, "Admin");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsJsonResult()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }
}

